// Extrair e normalizar dados do email recebido
const item = $input.first().json;

// --- Extrair from_email e from_name ---
const rawFrom = item.from || '';
// Formato possivel: "Nome Sobrenome <email@dominio.com>" ou apenas "email@dominio.com"
const emailMatch = rawFrom.match(/<([^>]+)>/);
const fromEmail = emailMatch ? emailMatch[1].trim() : rawFrom.trim();
const fromName = rawFrom.replace(/<[^>]+>/, '').replace(/"/g, '').trim() || fromEmail;

// --- Limpar subject (remover prefixos Re:, Fwd:, Enc:, FWD:, RES:) ---
const rawSubject = item.subject || '';
const cleanSubject = rawSubject
  .replace(/^\s*(Re|Fwd|Fw|Enc|FWD|RES|ENC|AW|WG)\s*:\s*/gi, '')
  .trim()
  || '(sem assunto)';

// --- Extrair body ---
const bodyText = item.text || item.textAsHtml?.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim() || '';
const bodyHtml = item.html || item.textAsHtml || '';

// --- Validacao minima ---
if (!fromEmail || !fromEmail.includes('@')) {
  return [{ json: { _valid: false, _error: 'Remetente invalido ou ausente', raw_from: rawFrom } }];
}

if (!cleanSubject || cleanSubject === '(sem assunto)') {
  console.warn('[crm-email-ingest] email sem assunto de:', fromEmail);
}

return [{
  json: {
    _valid: true,
    from_email: fromEmail,
    from_name: fromName,
    clean_subject: cleanSubject,
    body_text: bodyText.slice(0, 10000),
    body_html: bodyHtml.slice(0, 50000),
    received_at: item.date || new Date().toISOString()
  }
}];

// Logar sucesso da criacao
const ingestResult = $('POST /crm/ingest-email').item.json;
const parsedEmail = $('Parse Email Data').item.json;

console.log('[crm-email-ingest] oportunidade criada com sucesso', {
  opportunity_id: ingestResult.data?.opportunity_id,
  title: ingestResult.data?.title,
  from_email: parsedEmail.from_email,
  subject: parsedEmail.clean_subject
});

return [{ json: { success: true, ...ingestResult.data } }];

// Preparar dados para notificacao de erro (resposta da API sem opportunity_id)
const ingestResult = $('POST /crm/ingest-email').item.json;
const parsedEmail = $('Parse Email Data').item.json;

const errorDetail = ingestResult.error
  ? `${ingestResult.error}: ${ingestResult.message || ''}`
  : JSON.stringify(ingestResult).slice(0, 500);

console.error('[crm-email-ingest] falha ao criar oportunidade', {
  from_email: parsedEmail.from_email,
  subject: parsedEmail.clean_subject,
  error: errorDetail
});

return [{
  json: {
    _error: errorDetail,
    from_email: parsedEmail.from_email,
    from_name: parsedEmail.from_name,
    subject: parsedEmail.clean_subject
  }
}];

// Capturar erro de conexao ou timeout no HTTP Request
const item = $input.first().json;
const parsedEmail = $('Parse Email Data').item.json;

const errorMsg = item.error?.message || item.message || 'Falha na chamada HTTP para Supabase';

console.error('[crm-email-ingest] erro HTTP ao chamar ingest-email', {
  from_email: parsedEmail.from_email,
  subject: parsedEmail.clean_subject,
  error: errorMsg
});

return [{
  json: {
    _error: errorMsg,
    from_email: parsedEmail.from_email,
    from_name: parsedEmail.from_name,
    subject: parsedEmail.clean_subject
  }
}];

// Email invalido - logar e ignorar silenciosamente
const item = $input.first().json;
console.warn('[crm-email-ingest] email ignorado por falha de validacao', {
  error: item._error,
  raw_from: item.raw_from
});
return [{ json: { skipped: true, reason: item._error } }];

// Node de error handler global do workflow
const error = $input.first().json;
console.error('[crm-email-ingest] ERRO NAO TRATADO no workflow:', JSON.stringify(error).slice(0, 1000));
return [{ json: { handled: false, error: error } }];
